#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> bfs(vector<vector<int>>& graph, int source) {
        vector<bool> visited(graph.size(), false);
        vector<int> traversalOrder;
        queue<int> q;
        q.push(source);
        visited[source] = true;

        while (!q.empty()) {
            int vertex = q.front();
            q.pop();
            traversalOrder.push_back(vertex);
            for (int neighbor : graph[vertex]) {
                if (!visited[neighbor]) {
                    q.push(neighbor);
                    visited[neighbor] = true;
                }
            }
        }

        return traversalOrder;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> graph(V);
    for (int i = 0; i < E; i++) {
        int u, v;
        if (!(cin >> u >> v)) return 0;
        graph[u].push_back(v);
        graph[v].push_back(u);
    }
    int S;
    if (!(cin >> S)) return 0;
    Solution sol;
    vector<int> ans = sol.bfs(graph, S);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
